module.exports = "          '</div>' +\n          '<div class=\"drawer-section\">' +\n            '<h4 class=\"section-heading\">Runtime</h4>' +\n            '<pre class=\"team-drawer-pre\">' + esc(JSON.stringify(runtime || {}, null, 2)) + '</pre>' +\n          '</div>' +\n          (runtime.log_tail ? '<div class=\"drawer-section\"><h4 class=\"section-heading\">Run Log Tail</h4><pre class=\"team-drawer-pre tall\">' + esc(runtime.log_tail) + '</pre></div>' : '') +\n          (resultText ? '<div class=\"drawer-section\"><h4 class=\"section-heading\">Result Envelope</h4><pre class=\"team-drawer-pre\">' + esc(resultText) + '</pre></div>' : '') +\n          '<div class=\"drawer-section\">' +\n            '<h4 class=\"section-heading\">Task JSON</h4>' +\n            '<pre class=\"team-drawer-pre tall\">' + esc(taskJson) + '</pre>' +\n          '</div>';\n        drawer.querySelectorAll(\"[data-team-drawer-open-file]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({\n              type: \"openLocalFile\",\n              path: node.dataset.teamDrawerOpenFile || \"\",\n              label: node.dataset.teamDrawerOpenFileLabel || \"Opened file\",\n            });\n          });\n        });\n        drawer.querySelectorAll(\"[data-team-drawer-retry-task]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({\n              type: \"retryTeamTask\",\n              taskId: node.dataset.teamDrawerRetryTask || \"\",\n              mode: node.dataset.teamDrawerRetryMode || \"same\",\n            });\n          });\n        });\n        drawer.querySelectorAll(\"[data-team-drawer-restart-task]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({ type: \"restartTeamTask\", taskId: node.dataset.teamDrawerRestartTask || \"\" });\n          });\n        });\n        drawer.querySelectorAll(\"[data-team-drawer-delete-task]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({ type: \"deleteTeamTask\", taskId: node.dataset.teamDrawerDeleteTask || \"\" });\n          });\n        });\n        drawer.querySelectorAll(\"[data-team-drawer-copy-text]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({\n              type: \"copyText\",\n              text: node.dataset.teamDrawerCopyText || \"\",\n              label: node.dataset.teamDrawerCopyLabel || \"Copied\",\n            });\n          });\n        });\n        drawer.querySelectorAll(\"[data-focus-thread]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const threadId = node.dataset.focusThread || \"\";\n            if (!threadId) return;\n            setSelectedThread(threadId, { openDrawer: true });\n            vscode.postMessage({ type: \"selectThread\", threadId });\n            render(state.payload);\n          });\n        });\n        drawer.querySelectorAll(\"[data-codex-thread]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const threadId = node.dataset.codexThread || \"\";\n            if (!threadId) return;\n            markCodexLinking(threadId, \"sidebar\");\n            render(state.payload);\n            vscode.postMessage({ type: \"revealInCodexSidebar\", threadId });\n          });\n        });\n        drawer.querySelectorAll(\"[data-open-codex-editor]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const threadId = node.dataset.openCodexEditor || \"\";\n            if (!threadId) return;\n            markCodexLinking(threadId, \"editor\");\n            render(state.payload);\n            vscode.postMessage({ type: \"openInCodexEditor\", threadId });\n          });\n        });\n        return true;\n      }\n\n      function renderDetail(payload) {\n        const drawer = document.getElementById(\"threadDrawer\");\n        const backdrop = document.getElementById(\"drawerBackdrop\");\n        const title = document.getElementById(\"drawerTitle\");\n        const meta = document.getElementById(\"drawerMeta\");\n        const summaryNode = document.getElementById(\"drawerSummary\");\n        const actionsNode = document.getElementById(\"drawerActions\");\n        const body = document.getElementById(\"drawerBody\");\n        const context = buildDrawerDetailContext(payload);\n        const { detail } = context;\n        if (!(drawer && backdrop && title && meta && summaryNode && actionsNode && body)) return;\n\n        const teamTask = findTeamTaskForDrawer(payload, state.ui.teamTaskDrawerId);\n        if (state.ui.drawerOpen && teamTask) {\n          clearPendingDrawerAction();\n          renderTeamTaskDrawer(payload, teamTask);\n          return;\n        }\n        if (state.ui.teamTaskDrawerId && !teamTask) {\n          state.ui.teamTaskDrawerId = undefined;\n        }\n\n        if (!state.ui.drawerOpen) {\n          clearPendingDrawerAction();\n          state.ui.teamTaskDrawerId = undefined;\n          state.ui.optimisticDrawerThread = undefined;\n          drawer.classList.remove(\"open\");\n          backdrop.classList.remove(\"open\");\n          title.textContent = \"Thread detail\";\n          meta.innerHTML = \"\";\n          summaryNode.innerHTML = \"\";\n          actionsNode.innerHTML = \"\";\n          body.innerHTML = '<div class=\"drawer-section\"><div class=\"empty\">Select a thread to inspect details.</div></div>';\n          return;\n        }\n\n        if (!detail || !detail.thread) {\n          const optimisticThread = state.ui.optimisticDrawerThread || findThreadInPayload(state.selectedThreadId) || { id: state.selectedThreadId || \"\" };\n          const optimisticSummary = findThreadInPayload(optimisticThread.id) || optimisticThread;\n          drawer.classList.add(\"open\");\n          backdrop.classList.add(\"open\");\n          title.textContent = displayThreadTitle(optimisticSummary, \"Thread detail\");\n          meta.innerHTML = [\n            renderThreadFactBadges(optimisticSummary, payload),\n            renderCopyableThreadId(optimisticThread.id || state.selectedThreadId || \"\", { full: true }),\n            '<span class=\"meta-pill\">Loading detail</span>'\n          ].join(\"\");\n          summaryNode.innerHTML = [\n            drawerStat(\"Updated\", optimisticSummary.updated_age || optimisticSummary.updated_at_iso || \"-\"),\n            drawerStat(\"Process\", (optimisticSummary.process && optimisticSummary.process.summary) || \"Loading\"),\n            drawerStat(\"Commands\", String(threadCommandCount(optimisticSummary))),\n          ].join(\"\");\n          actionsNode.className = \"action-rail\";\n          actionsNode.innerHTML = renderTerminalResumeButton(optimisticThread, { className: \"action-btn secondary\", label: \"Resume Terminal\" }) +\n            '<span class=\"action-status\">Loading full inspector detail...</span>';\n          body.innerHTML = '<div class=\"drawer-section drawer-loading-section\"><div class=\"drawer-loading-title\">Opening inspector</div><div class=\"sub\">Showing cached thread summary while the session detail is loading.</div></div>';\n          bindCopyThreadIdActions(drawer);\n          return;\n        }\n\n        const {\n          thread,\n          summary,\n          logs,\n          history,\n          isArchived,\n          isSoftDeleted,\n          processText,\n          linkLabel,\n          visibilityLabel,\n          phase,\n          phaseClass,\n          coordination,\n          pendingDrawerAction,\n          confirmMeta,\n          actionNotice,\n        } = context;\n        const hardDeleteAction = canDispatchHardDeleteRequest()\n          ? renderActionButton(\"hard_delete\", \"Hard Delete\", \"danger\", \"HD\", thread.id || \"\")\n          : \"\";\n        if (state.ui.pendingDrawerAction && !pendingDrawerAction) {\n          clearPendingDrawerAction();\n        }\n        drawer.classList.add(\"open\");\n        backdrop.classList.add(\"open\");\n        state.ui.optimisticDrawerThread = undefined;\n        title.textContent = displayThreadTitle(Object.assign({}, summary, thread), \"Thread detail\");\n        meta.innerHTML = renderDrawerMeta(thread, summary, payload, phase);\n        summaryNode.innerHTML = renderDrawerSummaryStats(thread, summary, logs, phase, coordination, visibilityLabel, linkLabel, processText);\n        actionsNode.className = \"action-rail\" + (pendingDrawerAction ? \" confirm\" + (confirmMeta.tone === \"danger\" ? \" danger\" : \"\") : \"\");\n        actionsNode.innerHTML = renderDrawerActionRail(thread, summary, coordination, isArchived, isSoftDeleted, pendingDrawerAction, confirmMeta, hardDeleteAction, actionNotice);\n        body.innerHTML = renderDrawerBodySections(detail, thread, summary, logs, history, payload, phase, phaseClass, coordination);\n        document.querySelectorAll(\"[data-lifecycle-action]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const action = node.dataset.lifecycleAction;\n            const threadId = node.dataset.lifecycleThread;\n            if (action === \"hard_delete\" || action === \"soft_delete\") {\n              if (action === \"hard_delete\" && !canDispatchHardDeleteRequest()) return;\n              setPendingDrawerAction(threadId, action);\n              render(state.payload);\n              return;\n            }\n            if (!canDispatchLifecycleRequest()) return;\n            vscode.postMessage({ type: \"lifecycle\", action, threadId });\n          });\n        });\n        document.querySelectorAll(\"[data-quick-action]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const action = node.dataset.quickAction;\n            const threadId = node.dataset.quickThread;\n            if (action === \"thread_trace\") {\n              state.ui.threadDrawerMode = \"trace\";\n              render(state.payload);\n              return;\n            }\n            if (action === \"thread_conversation\") {\n              state.ui.threadDrawerMode = \"conversation\";\n              render(state.payload);\n              return;\n            }\n            if (action === \"thread_overview\") {\n              state.ui.threadDrawerMode = \"overview\";\n              render(state.payload);\n              return;\n            }\n            if (action === \"open_editor\") {\n              markCodexLinking(threadId, \"editor\");\n              render(state.payload);\n              vscode.postMessage({ type: \"openInCodexEditor\", threadId });\n              return;\n            }\n            if (action === \"set_handoff\") {\n              upsertHandoffCue(threadId);\n              return;\n            }\n            if (action === \"clear_handoff\") {\n              clearHandoffCue(thread.id || \"\");\n              return;\n            }\n            if (action === \"focus_handoff_target\") {\n              setSelectedThread(threadId, { openDrawer: true });\n              vscode.postMessage({ type: \"selectThread\", threadId });\n              return;\n            }\n            if (action === \"show_in_codex\") {\n              markCodexLinking(threadId, \"editor\");\n              render(state.payload);\n              vscode.postMessage({\n                type: \"showThreadInCodex\",\n                threadId,\n                preferredTitle: node.dataset.quickTitle || \"\",\n              });\n              return;\n            }\n            if (action === \"sidebar\") {\n              markCodexLinking(threadId, \"sidebar\");\n              render(state.payload);\n              vscode.postMessage({ type: \"revealInCodexSidebar\", threadId });\n            }\n          });\n        });\n        document.querySelectorAll(\"[data-drawer-cancel]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            clearPendingDrawerAction();\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-drawer-confirm]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const action = node.dataset.drawerConfirm;\n            const threadId = node.dataset.drawerThread;\n            clearPendingDrawerAction();\n            render(state.payload);\n            if (action === \"hard_delete\" && !canDispatchHardDeleteRequest()) return;\n            if (!canDispatchLifecycleRequest()) return;\n            vscode.postMessage({ type: \"lifecycle\", action, threadId });\n          });\n        });\n        document.querySelectorAll(\"[data-drawer-open-file]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({\n              type: \"openLocalFile\",\n              path: node.dataset.drawerOpenFile || \"\",\n              label: node.dataset.drawerOpenFileLabel || \"Opened file\",\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-conversation-jump]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const index = String(Number(node.dataset.conversationJump || 0));\n            const target = document.querySelector('[data-conversation-turn=\"' + index + '\"]');\n            if (!target) return;\n            target.scrollIntoView({ block: \"center\", behavior: \"smooth\" });\n            target.classList.remove(\"conversation-turn-highlight\");\n            void target.offsetWidth;\n            target.classList.add(\"conversation-turn-highlight\");\n          });\n        });\n        document.querySelectorAll(\"[data-conversation-locator-search]\").forEach((node) => {\n          node.addEventListener(\"input\", () => {\n            const query = String(node.value || \"\").trim().toLowerCase();\n            const locator = node.closest(\"[data-conversation-locator]\");\n            if (!locator) return;\n            locator.querySelectorAll(\"[data-conversation-jump]\").forEach((item) => {\n              const text = String(item.textContent || \"\").toLowerCase();\n              item.hidden = Boolean(query && !text.includes(query));\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-export-trace-report]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            vscode.postMessage({\n              type: \"exportTraceReport\",\n              threadId: node.dataset.exportTraceReport || \"\",\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-generate-thread-advice]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const threadId = node.dataset.generateThreadAdvice;\n            if (!threadId || node.disabled) return;\n            vscode.postMessage({\n              type: \"generateThreadVibeAdvice\",\n              threadId,\n              force: true,\n            });\n          });\n        });\n      }\n";
